create table dirkspzm32.pzm_konten_bh (
    sid                 varchar2(2 char) not null enable,
    firma_nr            number(6, 0) not null enable,
    konto_nr            number(*, 0) not null enable,
    pers_nr             number(*, 0) not null enable,
    kst_id              number(*, 0),
    konten_bh_id        number(*, 0) not null enable,
    buch_datum          date not null enable,
    bus                 number(*, 0) not null enable,
    wert                number(*, 5) not null enable,
    einheit             varchar2(20 char) not null enable,
    zk_start            date,
    zk_aa_id            number(*, 0),
    info                varchar2(255 char),
    typ                 varchar2(10 char) default 'B' not null enable,
    storno_konten_bh_id number(*, 0),
    abt_id              number(*, 0),
    created_date        date default sysdate not null enable,
    created_login_id    number(*, 0) default - 1 not null enable,
    created_user        varchar2(255 char)
);

alter table dirkspzm32.pzm_konten_bh
    add constraint pk_pzm_konten_bh
        primary key ( konten_bh_id,
                      firma_nr,
                      sid )
            using index enable;


